class CourseDetailScreen extends ConsumerStatefulWidget{final int courseId;const CourseDetailScreen({super.key,required this.courseId});@override ConsumerState<CourseDetailScreen> createState()=>_S();}
class _S extends ConsumerState<CourseDetailScreen>{Course? _c;bool _loading=true;@override void initState(){super.initState();_load();}Future<void> _load()async{final r=ref.read(courseRepositoryProvider);final cs=await r.getAllCourses();setState((){_c=cs.where((c)=>c.id==widget.courseId).firstOrNull;_loading=false;});}Future<void> _del()async{final ok=await showDialog<bool>(context:context,builder:(c)=>AlertDialog(title:const Text('del'),content:Text('del ${_c?.name}?'),actions:[TextButton(onPressed:()=>Navigator.pop(c,false),child:const Text('cancel')),FilledButton(onPressed:()=>Navigator.pop(c,true),style:FilledButton.styleFrom(backgroundColor:AppColors.error),child:const Text('del'))]));if(ok==true&&_c?.id!=null){await ref.read(courseRepositoryProvider).deleteCourse(_c!.id!);if(mounted){Navigator.pop(context);}}}@override Widget build(BuildContext c){if(_loading)return Scaffold(appBar:AppBar(title:const Text('detail')),body:const Center(child:CircularProgressIndicator()));if(_c==null)return Scaffold(appBar:AppBar(title:const Text('detail')),body:const Center(child:Text('not found')));final course=_c!;final color=_pc(course.colorHex);return Scaffold(appBar:AppBar(title:const Text('detail'),actions:[IconButton(icon:const Icon(Icons.edit_outlined),tooltip:'edit',onPressed:(){c.pushNamed('course_edit',pathParameters:{'id':'${course.id}'});}),IconButton(icon:const Icon(Icons.delete_outline,color:AppColors.error),onPressed:_del)]),body:SingleChildScrollView(padding:const EdgeInsets.all(20),child:Column(crossAxisAlignment:CrossAxisAlignment.start,children:[Container(width:double.infinity,padding:const EdgeInsets.all(20),decoration:BoxDecoration(color:color,borderRadius:BorderRadius.circular(16)),child:Column(crossAxisAlignment:CrossAxisAlignment.start,children:[Text(course.name,style:AppTextStyles.heading1.copyWith(color:Colors.white)),if(course.teacher.isNotEmpty)Padding(padding:const EdgeInsets.only(top:8),child:Text(course.teacher,style:AppTextStyles.body.copyWith(color:Colors.white70))),])),const SizedBox(height:24),_sect('info',[_row('day','周${AppConstants.weekDayNames[course.dayOfWeek-1]}'),_row('section','${course.startSection}-${course.endSection}节'),_row('place',course.location.isEmpty?'unk':course.location)]),const SizedBox(height:16),_sect('weeks',[_wkChips(course.weeks),const SizedBox(height:12),Row(children:[OutlinedButton.icon(icon:const Icon(Icons.block,size:16),label:const Text('本周停课'),style:OutlinedButton.styleFrom(foregroundColor:AppColors.warning),onPressed:()=>_tw(false,course)),const SizedBox(width:12),OutlinedButton.icon(icon:const Icon(Icons.restore,size:16),label:const Text('本周复课'),style:OutlinedButton.styleFrom(foregroundColor:AppColors.success),onPressed:()=>_tw(true,course))])])])));}Widget _sect(String t,List<Widget> w)=>Column(crossAxisAlignment:CrossAxisAlignment.start,children:[Text(t,style:AppTextStyles.heading3),const SizedBox(height:8),Card(child:Padding(padding:const EdgeInsets.all(16),child:Column(children:w)))]);Widget _row(String l,String v)=>Padding(padding:const EdgeInsets.symmetric(vertical:4),child:Row(children:[SizedBox(width:80,child:Text(l,style:AppTextStyles.bodySmall)),Expanded(child:Text(v,style:AppTextStyles.body.copyWith(color:AppColors.textPrimary)))]));Widget _wkChips(List<int> wks){final cw=_cw();return Wrap(spacing:8,runSpacing:8,children:wks.map((w){final isCur=w==cw;return Container(padding:const EdgeInsets.symmetric(horizontal:10,vertical:5),decoration:BoxDecoration(color:isCur?AppColors.primary.withOpacity(0.15):AppColors.surfaceVariant,borderRadius:BorderRadius.circular(6),border:isCur?Border.all(color:AppColors.primary,width:1):null),child:Text('$w周',style:TextStyle(fontSize:12,fontWeight:isCur?FontWeight.bold:FontWeight.normal,color:isCur?AppColors.primary:AppColors.textSecondary)));}).toList());}int _cw(){final n=DateTime.now();final ss=DateTime(n.year,n.month>=9?9:2,1);return((n.difference(ss).inDays)/7).ceil().clamp(1,20);}Future<void> _tw(bool add,Course course)async